Query.Sql:
select distinct Record ->> '$.LinkagePatientId.NhsNumber.@extension' as NhsNumber,
Record ->> '$.DiagnosticProcedures.DiagnosticProcedureOpcs.@code' as DiagnosticProcedureOpcs,
Record ->> '$.DiagnosticProcedures.DiagnosticProcedureDate' as DiagnosticProcedureDate from omop_staging.cosd_staging_901 where type = 'UG' and NhsNumber is not null and DiagnosticProcedureOpcs is not null;
